example.code:
if (Prime.Base.ServiceStore<IDffService>.Service.TryGetVidPerUlt("Y5106803_330_-10_+00", out var vid, sessionContext))
{
    Prime.Base.ServiceStore<IDffService>.Service.Print($"Current Ult's Vid=[{vid}].");
}
else
{
    Prime.Base.ServiceStore<IDffService>.Service.Print($"Sorry, but we couldn't find the match of Ult in UBE file..");
}

if (Prime.Base.ServiceStore<IDffService>.Service.TryGetUltFromUbePerDieId("UnitVisualId", out var ult, sessionContext))
{
    Prime.Base.ServiceStore<IDffService>.Service.Print($"Current ult at DieId under vid=[{ult}].");
}
else
{
    Prime.Base.ServiceStore<IDffService>.Service.Print($"Sorry, but we couldn't find the match of dieId in UBE file..");
}

